SELECT m.member_id, m.company_id, m.user_id, m.name, m.email, m.tel_no, m.reg_id, m.reg_dt, m.chg_id, m.chg_dt, m.del_yn, c.company_nm, ur.role_id FROM member m LEFT JOIN company c ON m.company_id = c.company_id LEFT JOIN user_role ur ON m.member_id = ur.member_id AND ur.del_yn = 'N' WHERE 1 = 1
AND m.member_id = #{memberId}
AND m.name LIKE CONCAT('%', #{name}, '%')
AND m.tel_no LIKE CONCAT('%', #{telNo}, '%')
AND m.member_id = #{memberId}
ORDER BY m.member_id DESC

