user_role
SET
chg_id = CASE



			WHEN member_id = #{userRole.memberId}
			AND role_id = #{userRole.roleId}
			THEN #{userRole.chgId}


			WHEN member_id = #{userRole.memberId}
			AND role_id = #{userRole.roleId}
