UPDATE member SET
company_id = #{companyId},
user_pw = #{userPw},
name = #{name}, email = #{email}, tel_no = REPLACE(#{telNo}, '-', ''), chg_id = #{chgId}, del_yn = #{delYn}, chg_dt = NOW() WHERE member_id = #{memberId}
