SELECT ur.member_id, ur.role_id, u.name, r.role_name, ur.reg_id, ur.reg_dt, ur.chg_id, ur.chg_dt, ur.del_id, ur.del_dt, ur.del_yn FROM user_role ur INNER JOIN member u ON ur.member_id = u.member_id INNER JOIN role r ON ur.role_id = r.role_id
AND ur.member_id IN
#{memberId}
AND ur.role_id IN
#{roleId}
AND u.name ILIKE '%' || #{filter.name} || '%'
AND r.role_name ILIKE '%' || #{filter.roleName} || '%'
AND ur.del_yn = #{filter.delYn}
AND u.del_yn = #{filter.parentIsActive} AND r.del_yn = #{filter.parentIsActive}
